#!/usr/bin/env bash
set -euo pipefail

ROOT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
OUT_DIR="$ROOT_DIR/homepage-display-assets"

mkdir -p "$OUT_DIR"

download() {
  local filename="$1"
  local url="$2"
  echo "Downloading $filename"
  curl -L --fail --silent --show-error "$url" -o "$OUT_DIR/$filename"
}

